INSERT INTO offmarket.business_scores (business_id,score_run_id,layer1_base_rate,layer1_comment,layer2_sellability,layer2_comment,layer3_behavioral_trigger,layer3_comment,layer4_market_pull,layer4_comment,final_score,final_tier,final_comment,value_add_thesis,confidence,data_completeness)
VALUES
  ('7d9786a3-9f74-4979-bfd1-d9a382fcbd8f','883fb301-0002-4bec-9478-b9d40e91f126',90.0,'Owners ~70 (3rd-gen daughters of 50-yr FDL Homer McCoy Jr.); 101-yr tenure (+4). High base.',70.0,'Solo FDL + preneed offered; no cemetery. 100-yr brand + Third Ward institutional embed.',72.0,'Tells: dated template website; no online preneed planner; 4th-gen ''begun working'' language=presence not handoff; 100yrs same MLK Blvd location.',82.0,'Houston metro (+5); Hispanic-adjacent Black-owned niche; SCI/Foundation Partners hunt Houston historic Black FHs.',78.0,'A_acquire_self','101yr Houston FH. Owner est ~70yr. A-tier.','Inherit 100-yr Houston Third Ward Black-owned brand. Add online preneed planner, cremation/celebration-of-life products, refresh website. Margin uplift via tech + retain 4th-gen as employee.','medium',0.7),
  ('71220d00-ba68-40c0-91bb-d1cd4d91a609','883fb301-0002-4bec-9478-b9d40e91f126',85.0,'Owners ~65 + succession event (+10): 2nd-gen leader Ron Crowder Sr. d. Dec 2022 age 74. Diffuse family ownership across brothers + nephew.',78.0,'Solo FDL chain with 5 locations across Galveston Bay corridor + preneed. Multi-FDL bench.',78.0,'Tells: 23 years since founders left; major Dec 2022 succession event; legacy website template; diffuse family equity = exit-readiness; 5 locations stretched post-death.',85.0,'Houston metro periphery (+5); Galveston Bay corridor demographically aging; Foundation Partners + Park Lawn active TX.',81.0,'A_acquire_self','67yr La Marque FH. Owner est ~65yr. A-tier.','Post-succession-event consolidation play. Buy 5-location Galveston Bay network. Refresh tech + preneed funnel, retain Crowder family in operational roles. Modernize bookkeeping; expected EBITDA uplift via central-billing.','medium',0.7),
  ('11fa94e2-1b06-47e2-9f01-eff91acbea69','883fb301-0002-4bec-9478-b9d40e91f126',92.0,'Founder ~75 (Howard 1973 + Baylor ENT 1978 = born ~1951); 29-yr tenure; classic post-70 founder exit window.',68.0,'Solo FDL + 4 FDLs + preneed; single location; distinctive Egyptian/Black-art branding = niche premium.',70.0,'Tells: founder is still ENT surgeon AND owner = dual-career exhaustion; Justin''s non-traditional path (LA/Qatar/author); single Almeda location 29 yrs; high-touch lower-volume positioning.',85.0,'Houston metro (+5); Museum District/Third Ward; Black-owned cultural-niche FH attractive to ETA preserving legacy.',78.0,'A_acquire_self','29yr Houston FH. Owner est ~75yr. A-tier.','Inherit distinctive cultural-niche brand. Founder is dual-career; willing to exit at right price. Son Justin can stay as FDL/operator. Add online preneed + cremation/celebration products, scale to 2-3 locations within 5 yrs.','medium',0.75),
  ('8f39528b-6f30-4a71-af35-5429496e4eae','883fb301-0002-4bec-9478-b9d40e91f126',88.0,'Charles II ~65, 34-yr tenure (+10 succession event: matriarch Lois Villaseñor d. COVID 7/2020 age 87); no 3rd-gen named publicly.',78.0,'Solo FDL + preneed; 4 locations (Heritage Chapel, Serenity Chapel, Los Angeles FH San Marcos, Mission Pet Memorials); Hispanic Mexican-American niche dominance.',80.0,'Tells: matriarch death 2020 emotional+ops blow; funeraltechweb.com subdomain (not own brand); no 3rd-gen heir named; UT Tower 1966 first-responder pride = deep roots; 34yr same operator.',92.0,'Austin major metro 85-90; Hispanic-heavy Mexican-American East Austin niche (+3); high-growth retiree boomer market.',84.0,'A_acquire_self','67yr Austin FH. Owner est ~65yr. A-tier.','Austin''s oldest family FH. Buy from post-matriarch-death operator (~65) with no clear successor. Mexican-American niche dominance + 4 location network (incl. pet memorial). Modernize tech, preserve Spanish-language identity. Strong A-tier.','medium',0.75),
  ('d6ad9805-2dd2-46b2-8ad7-a3fd35004795','883fb301-0002-4bec-9478-b9d40e91f126',92.0,'John M. Kreidler 77 (Air Force vet, Dec 1972 start = 54yr tenure); 114-yr business.',72.0,'3 FDLs + preneed; single location; OGR member; 1912 oldest McAllen FH = RGV market dominance.',50.0,'Strong 5-gen succession: William R. Kreidler VP since 2002 (24-yr tenure ~45-50). Orderly succession = LOWER seller probability unless price reflects 5-gen legacy.',90.0,'McAllen RGV Hispanic-heavy (+3); SCI/Foundation Partners active border markets; aging retiree.',74.0,'B_forward','114yr McAllen FH. Owner est ~77yr. B-tier.','Last-chance acquisition before full handoff to William. Premium price required to acquire 5-gen RGV legacy. Strong intra-family operator = will only sell at right valuation.','medium',0.85),
  ('67ad3121-55f2-4121-ae19-cf2830a173b1','883fb301-0002-4bec-9478-b9d40e91f126',95.0,'Widow-President ~72, 15-yr tenure post-husband death 2011 (+5 widow-running-solo); founder bloodline absent — non-family stewards since 1960.',70.0,'Solo FDL + preneed; single eastside SA location; 1909 historic Black-owned community pillar = high cultural-asset value.',82.0,'Tells: widow-operator since 2011; NO blood successor identified; About/Meet Team page 404''d (coasting tell); founder bloodline left since 1960; legacy at vulnerability inflection.',88.0,'SA major metro 80-90; Hispanic-heavy SA south +3; Black-owned cultural niche; consolidators chasing historic Black FHs.',84.0,'A_acquire_self','117yr San Antonio FH. Owner est ~72yr. A-tier.','Buy 117-yr SA Black-owned institution from widow-operator with no successor. Independent-operator ETA buyer = perfect counter-narrative to consolidator pitch. Modernize tech, preserve legacy. Highest-probability seller in batch 1.','medium',0.7),
  ('c3458fc3-398f-4a7f-929d-b2563416523a','883fb301-0002-4bec-9478-b9d40e91f126',93.0,'Craig Cates ~71, 45-yr tenure (+5 widower-running-solo); Mary Weller Cates d. 5/2020 removed Weller bloodline; founder-recently-deceased proxy.',92.0,'Cemetery (94 acres, first burial 1872) + funeral home + dual crematory (pet + human) + perpetual care trust = HIGHEST vertical integration in batch. 80-95 band.',78.0,'Tells: widower-operator since 2020; NO blood Weller successor; 45-yr tenure; former TFSC board (industry savvy, will want fair price); single integrated 94-acre property.',88.0,'SA major metro 80-90; cemetery component highly attractive to Park Lawn / SCI consolidators (+3); aging-population dynamics.',88.0,'A_acquire_self','63yr San Antonio FH. Owner est ~71yr. A-tier.','Premier vertical-integration target. 94-acre cemetery + perpetual care trust + dual crematory + 63-yr FH. Widower-operator ~71 with no blood successor = classic post-spouse exit window. Capital-intensive but extraordinary moat.','medium',0.85),
  ('a90fac7f-9bd9-46e8-a591-8d3184180d4e','883fb301-0002-4bec-9478-b9d40e91f126',60.0,'Owner age unknown (opacity tell); Antonio Castillo d. 2007 may be founder; affiliated ''Castillo Mission FH'' since 1936 suggests deeper lineage.',62.0,'Solo FDL + preneed; on-site crematory; single location; bilingual Mexican-American SA niche.',65.0,'Tells: website does NOT list owners/staff (major opacity); generic tagline; CFS template; possible link to older 1936 Castillo Mission entity.',88.0,'SA major metro 80-90; Hispanic-heavy SA south (+3); aging-retiree.',66.0,'B_forward','42yr San Antonio FH. Owner est ~Noneyr. B-tier.','Information-thin SA Mexican-American FH. Worth deep-dive via Comptroller/BBB to verify owner age + successor. If 60+ owner confirmed, could elevate to A.','low',0.5),
